cds-views-024.codeExamples:
-- DCL (Access Control) example for CDS view
@EndUserText.label: 'Sales Order Access Control'
@AccessControl.authorizationCheck: #CHECK
define role ZI_SALESORDER_ACCESS {
  grant select on ZI_SALESORDER_BASIC
    where (VKORG) = aspect pfcg_auth(V_VBAK_VKO, VKORG, ACTVT = '03');
}

-- CDS View with DCL association
@AbapCatalog.sqlViewName: 'ZV_SORD_BASIC'
@AccessControl.authorizationCheck: #CHECK
define view ZI_SALESORDER_BASIC
  as select from vbak
{
  vbeln,
  erdat,
  vkorg,
  netwr
}

-- PFCG Role check via ABAP (for verification)
AUTHORITY-CHECK OBJECT 'V_VBAK_VKO'
  FIELD 'VKORG' VALUE lv_vkorg
  FIELD 'ACTVT' VALUE '03'.
IF sy-subrc <> 0.
  MESSAGE 'No authorization' TYPE 'E'.
ENDIF.

